import{_ as r,o as e,c as s,ag as t}from"./chunks/framework.WmBmIPw-.js";const _=JSON.parse('{"title":"变邻域搜索（Variable Neighborhood Search, VNS）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/vns.md","filePath":"or-opt/vns.md","lastUpdated":1777121552000}'),o={name:"or-opt/vns.md"};function h(i,a,n,l,d,p){return e(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="变邻域搜索-variable-neighborhood-search-vns" tabindex="-1">变邻域搜索（Variable Neighborhood Search, VNS） <a class="header-anchor" href="#变邻域搜索-variable-neighborhood-search-vns" aria-label="Permalink to &quot;变邻域搜索（Variable Neighborhood Search, VNS）&quot;">​</a></h1><p>变邻域搜索由 Mladenović 与 Hansen 等系统化提出：在单点搜索框架下，预备一组由弱到强（或由近到远）的邻域结构，在局部最优处通过「换邻域」或「抖动 + 再局部搜索」跳出当前吸引域。与固定单邻域的下降法相比，显式利用多邻域的互补性，属单解、基于邻域的元启发式，见 <a href="./metaheuristics.html">元启发式总览</a>。</p><p><strong>适用</strong>：组合优化（路径、调度、划分等）与部分连续问题在能定义多个邻域算子且每步评价 f 可承受时；邻域设计对效果起决定作用。</p><p><strong>核心</strong>：当前解在某一邻域内做局部搜索直至局部最优后，若不能改进，则按规则切换到更大扰动范围的邻域（抖动）或换一套邻域结构再搜；成功改进则往往回到最小邻域继续细化。常与变邻域下降（VND）等子过程组合。</p><hr><h2 id="记号与邻域结构" tabindex="-1">记号与邻域结构 <a class="header-anchor" href="#记号与邻域结构" aria-label="Permalink to &quot;记号与邻域结构&quot;">​</a></h2><p>设目标 f(s) 最小化，s 为可行解。给定有限个邻域映射 N_k，k∈{1,…,K_max}，通常按「步幅」或「破坏程度」单调：N_1 最局部，N_Kmax 扰动最大。对点 s，N_k(s) 表示经第 k 类算子一步可达的邻域点集（实现上常从 N_k(s) 中采样或枚举子集）。</p><hr><h2 id="典型子过程-变邻域下降-vnd" tabindex="-1">典型子过程：变邻域下降（VND） <a class="header-anchor" href="#典型子过程-变邻域下降-vnd" aria-label="Permalink to &quot;典型子过程：变邻域下降（VND）&quot;">​</a></h2><p>VND 假定已有多邻域 N_1,…,N_K，无随机抖动，只做确定性局部最优传递。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 变邻域下降 VND</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>选定可行解 s，设 k ← 1。</p><h3 id="_2-在当前邻域内找改进" tabindex="-1">2. 在当前邻域内找改进 <a class="header-anchor" href="#_2-在当前邻域内找改进" aria-label="Permalink to &quot;2. 在当前邻域内找改进&quot;">​</a></h3><p>在 N_k(s) 中寻找使 f 下降的点 s′（依「首次改进」「最速下降」等规则，直到 N_k 内对 s 为局部最优）。</p><h3 id="_3-邻域切换" tabindex="-1">3. 邻域切换 <a class="header-anchor" href="#_3-邻域切换" aria-label="Permalink to &quot;3. 邻域切换&quot;">​</a></h3><p>若找到改进 s′，令 s ← s′，k ← 1（回到最细邻域继续）；若 N_k 内无改进，令 k ← k+1。</p><h3 id="_4-终止" tabindex="-1">4. 终止 <a class="header-anchor" href="#_4-终止" aria-label="Permalink to &quot;4. 终止&quot;">​</a></h3><p>若 k&gt;K（所有 N_k 对当前 s 均局部最优），停，输出 s；否则回到步骤 2。</p></div><p>VND 本身仍可能停在多邻域意义下的强局部优；基本 VNS 在此外层增加随机抖动以跳离。</p><hr><h2 id="抖动-shaking" tabindex="-1">抖动（Shaking） <a class="header-anchor" href="#抖动-shaking" aria-label="Permalink to &quot;抖动（Shaking）&quot;">​</a></h2><p><strong>作用</strong>：当当前 s 在某一局部搜索下已是局优时，若只在同一套确定性邻域里下降，会反复落回同一片吸引域。抖动的目标不是让单步 f 变小，而是利用随机性从 N_k(s) 里取新起点 s′，使随后局部搜索有机会进入新的谷地。s′ 可以明显劣于 s，也无需在 N_k 上对 f 做任何最优化，这与 VND 中「在 N_k 内找改进步」的取向相反。</p><p><strong>与邻域下标 k 的关系</strong>：k 标定「这一次抖动用哪一级邻域算子/步幅」。常令 k 自 1 递增至 K_max。k 较小时，一步只离开 s 的邻近位置，多在同一盆地内换起点；k 较大时，一步跨越更远、更易破坏当前结构，因而更常配合修复算子，并依赖内层 VND/下降把 s′ 收敛到新的局优。</p><p><strong>从 N_k(s) 中生成 s′ 的常见方式</strong>（实现上可择一或组合）：</p><ul><li>一步随机邻居：在 N_k(s) 的枚举/候选集合中等概率或加权抽一点。</li><li>多步随机游走：对固定 k 连续做 t 次「在 N_k 中抽随机邻步并前进一步」，t 可常数、与 k 成比例或上界内均匀随机，相当于用同一 N_k 工具堆出更强扰动而不另建一套邻域结构。</li><li>逆移与有偏：若仅防「立刻逆回上一步」即可减轻短循环，可与极轻量禁忌同用；若引入复杂记忆则更接近混合 TS，已超出「纯 VNS 抖动」的朴素表述，实现时需单独定稿。</li></ul><p><strong>可行性与修复</strong>：N_k 可能产生不可行 s′ 时，可丢弃后重试、在 N_k 上有限次重采样，或调问题相关修复把 s′ 投回可行集；再进入局部搜索。哪一级邻域易不可行、修复代价多大，是邻域设计的一部分。</p><p><strong>何时加大 k</strong>：外层的接受与更新若多次记录「s″ 不优于当前 s」，则把 k 加一，使下一次抖动在更大范围内抽 s′。语义上等价于小抖不动就换强抖，而不同于把每次搜索都变成全局大随机重启；层次化的 k 是基本 VNS 与「单次大扰动再搜」的常用分野。</p><p><strong>与内层局搜的分工</strong>：抖动只负责「把我扔到哪儿去」，内层 VND/下降负责「在新起点上尽量爬到局部最优」。重复「抖—搜」在随机性上比单邻域里串很长一串随机可接受非改进步更短、也更容易控计算量，因为坏起点不必沿轨迹一路滚下去，可立即进入下一轮 k 的抖动。</p><hr><h2 id="基本-vns-主循环-最小化示意" tabindex="-1">基本 VNS 主循环（最小化示意） <a class="header-anchor" href="#基本-vns-主循环-最小化示意" aria-label="Permalink to &quot;基本 VNS 主循环（最小化示意）&quot;">​</a></h2><p>主循环中每一步「抖动」即上节对 N_k 与 s′ 的约定；下框只保留接口级步骤。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 基本 VNS（单解、多邻域 + 抖动）</p><h3 id="_1-初始化-1" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化-1" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>生成初始解 s，记历史最优 s⋆ ← s。设邻域族 N_1,…,N_K 与最大抖动强度 K_max。可选：内层用 VND 或固定顺序单邻域下降。</p><h3 id="_2-外层邻域下标" tabindex="-1">2. 外层邻域下标 <a class="header-anchor" href="#_2-外层邻域下标" aria-label="Permalink to &quot;2. 外层邻域下标&quot;">​</a></h3><p>设 k ← 1，表示当前抖动使用的邻域级别。</p><h3 id="_3-抖动" tabindex="-1">3. 抖动 <a class="header-anchor" href="#_3-抖动" aria-label="Permalink to &quot;3. 抖动&quot;">​</a></h3><p>按上节「抖动（Shaking）」在 N_k 上自 s 生成 s′。</p><h3 id="_4-局部搜索" tabindex="-1">4. 局部搜索 <a class="header-anchor" href="#_4-局部搜索" aria-label="Permalink to &quot;4. 局部搜索&quot;">​</a></h3><p>以 s′ 为起点，在全部或部分邻域上执行 VND/下降，得局部最优点 s″。</p><h3 id="_5-接受与邻域级更新" tabindex="-1">5. 接受与邻域级更新 <a class="header-anchor" href="#_5-接受与邻域级更新" aria-label="Permalink to &quot;5. 接受与邻域级更新&quot;">​</a></h3><p>若 f(s″)&lt;f(s)，令 s ← s″，k ← 1，若 f(s″)&lt;f(s⋆) 则 s⋆ ← s″；否则 k ← k+1。若 k&gt;K_max，可 k ← 1 并配合全局迭代上限或 s ← s″ 的变体，依实现定稿。</p><h3 id="_6-终止" tabindex="-1">6. 终止 <a class="header-anchor" href="#_6-终止" aria-label="Permalink to &quot;6. 终止&quot;">​</a></h3><p>达时间、总评价次数、连续无改进步数等，输出 s⋆。</p></div><hr><h2 id="关键要素" tabindex="-1">关键要素 <a class="header-anchor" href="#关键要素" aria-label="Permalink to &quot;关键要素&quot;">​</a></h2><p><strong>邻域族顺序</strong>：k 小对应小扰动、利于微调；k 大利于跳出，但过强抖动易损可行或需修复算子。实践上常问题特化设计多种 2-opt、insert、swapping、大规模破坏—修复等，并在 N_k 间保持可实现的评价代价。与抖动强度的关系见上文「抖动（Shaking）」专节。</p><p><strong>与禁忌搜索、模拟退火</strong>：VNS 用「多邻域结构 + 显式改变搜索邻域/抖动范围」管理探索，不必依赖禁忌表或温度；也可与 TS/SA 混合为同一内层或外层。</p><p><strong>扩展</strong>：如简化 VNS（reduced VNS）限制抖动与搜索子集、并行 VNS、及在全局框架中与精确子程序、大规模邻域搜索衔接，均属实现与文献变体，本页不逐条列参。</p>',30)])])}const c=r(o,[["render",h]]);export{_ as __pageData,c as default};
